style.css.data:
@media print {
  @page {
    size: A4 landscape;
    @bottom-right {
      font-family: Tahoma;
      font-size: 8pt;
      /* do not allow formatter to add a line break in the content */
      /* prettier-ignore*/
      content: '{{t(k="report.page",f="Page")}} ' counter(page) ' {{t(k="report.of",f="of")}} ' counter(pages);
    }
  }
}

.logo {
  display: block;
  height: 96px;
}

.header_image_section,
.header_supplied_section,
.header_date_section,
.body_section,
.body_total_section {
  margin-left: 8px;
  width: 100%;
}

.header_supplied_section {
  width: 100%;
  font-family: Tahoma;
  font-size: 8pt;
  border-bottom: 0.5px solid black;
}

.header_image_section {
  width: 100%;
  font-family: Tahoma;
  font-size: 8pt;
  border-bottom: 0.5px solid black;
  padding-top: 8pt;
}

.header_date_section {
  width: 100%;
  font-family: Tahoma;
  font-size: 8pt;
  border-bottom: 0.5px solid black;
  padding-top: 1pt;
}

.header_section_field_right {
  text-align: right;
  font-family: Tahoma;
  font-size: 8pt;
}

.header_section_field_left {
  text-align: left;
  font-family: Tahoma;
  font-size: 8pt;
}

.line_number,
.quantity,
.pack,
.expiry,
.cost_price,
.total_quantity,
.total_extension {
  text-align: right;
  font-family: Tahoma;
  font-size: 8pt;
}

.location_code,
.item_name,
.batch {
  text-align: left;
  font-family: Tahoma;
  font-size: 8pt;
}

.body_section,
.body_total_section {
  width: 100%;
  font-family: Tahoma;
}

.body_section tr.body_column_label th {
  border-bottom: 0.5px solid black;
}

.body_value td {
  border-bottom: 0.5px solid black;
}

hr {
  width: 100%;
  margin-left: 8px;
  border: 0.1px solid black;
}

.header_left_section {
  text-align: left;
  font-family: Tahoma;
  font-size: 8pt;
  flex: 0 1 auto;
  margin-right: 10px;
}

.header_details_section {
  flex: 1 1 0;
  text-align: left;
  font-family: Tahoma;
  font-size: 8pt;
}

.header_right_section {
  text-align: right;
  font-family: Tahoma;
  font-size: 8pt;
  flex: 0 1 auto;
}

.batch-wrap {
  word-break: break-word;
}

data.query:
query InvoiceQuery(
  $storeId: String!
  $dataId: String!
  $sort: PrintReportSortInput
) {
  invoice(storeId: $storeId, id: $dataId) {
    ... on InvoiceNode {
      id
      otherPartyId
      comment
      status
      invoiceNumber
      theirReference
      createdDatetime
      pickedDatetime
      shippedDatetime
      deliveredDatetime
      allocatedDatetime
      otherPartyName
      type
      pricing {
        serviceTotalAfterTax
        serviceTotalBeforeTax
        stockTotalAfterTax
        stockTotalBeforeTax
        taxPercentage
        totalAfterTax
        totalBeforeTax
      }
      otherParty(storeId: $storeId) {
        name
        id
        isSupplier
        isCustomer
        code
        address1
        address2
      }
      purchaseOrder {
        number
      }
      user {
        username
      }
    }
    ... on NodeError {
      __typename
      error {
        description
      }
    }
  }
  invoiceLines(
    storeId: $storeId
    filter: { invoiceId: { equalTo: $dataId } }
    reportSort: $sort
  ) {
    ... on InvoiceLineConnector {
      nodes {
        id
        itemId
        itemCode
        itemName
        locationName
        item {
          unitName
        }
        packSize
        expiryDate
        batch
        numberOfPacks
        packSize
        sellPricePerPack
        costPricePerPack
        pricing {
          serviceTotalAfterTax
          serviceTotalBeforeTax
          stockTotalAfterTax
          stockTotalBeforeTax
          taxPercentage
          totalAfterTax
          totalBeforeTax
        }
        location {
          code
        }
      }
    }
  }
  store(id: $storeId) {
    ... on StoreNode {
      code
      storeName
      logo
      id
      name(storeId: $storeId) {
        address1
        address2
        chargeCode
        code
        comment
        country
        email
        name
        phone
        website
      }
    }
  }
}

data.template:
// Test data — replaced with real data at report generation time
#let report_data = (
