        address1: "456 Supplier Road",
        address2: "",
      ),
      theirReference: "PO#4-A",
      createdDatetime: "2024-01-15T00:00:00Z",
      deliveredDatetime: "2024-01-16T00:00:00Z",
      shippedDatetime: none,
      purchaseOrder: none,
      user: (username: "Admin"),
      pricing: (
